static cJSON *waas_revoke_access_request_to_json(const waas_revoke_access_request *value) {
    if (!value) return cJSON_CreateObject();
    cJSON *root = cJSON_CreateObject();
    if (!root) return NULL;
    {
            cJSON *field_json = NULL;

    field_json = value->params ? waas_revoke_access_params_to_json(value->params) : cJSON_CreateNull();
    if (!field_json) goto fail;
            cJSON_AddItemToObject(root, "params", field_json);
    }
    return root;
fail:
    cJSON_Delete(root);
    return NULL;
}

static int waas_revoke_access_response_from_json(const cJSON *json, waas_revoke_access_response *out, waas_error *error) {
    if (!out) {
        waas_set_error(error, 0, 0, "DecodeError", "output pointer is NULL", NULL);
        return -1;
    }
    if (!json || !cJSON_IsObject(json)) {
        waas_set_error(error, 0, 0, "DecodeError", "expected JSON object", NULL);
        return -1;
    }
    {
        const cJSON *field_json = cJSON_GetObjectItemCaseSensitive(json, "ok");
        if (!field_json || cJSON_IsNull(field_json)) {
            waas_set_error(error, 0, 0, "DecodeError", "missing required field ok", NULL);
            goto fail;
        }

    if (!cJSON_IsBool(field_json)) {
        waas_set_error(error, 0, 0, "DecodeError", "expected boolean", NULL);
        goto fail;
    }
    out->ok = cJSON_IsTrue(field_json);
    }
    return 0;
fail:
    waas_revoke_access_response_free(out);
    return -1;
}

