struct waas_wallet_client {
    char *base_url;
    char *bearer_token;
    struct curl_slist *default_headers;
    long timeout_ms;
};

static void waas_wallet_client_reset_config(waas_wallet_client *client) {
    if (!client) return;
    free(client->bearer_token);
    client->bearer_token = NULL;
    if (client->default_headers) {
        curl_slist_free_all(client->default_headers);
        client->default_headers = NULL;
    }
    client->timeout_ms = 10000L;
}

int waas_wallet_client_configure(waas_wallet_client *client, const waas_client_options *options) {
    if (!client) return 0;

    waas_wallet_client_reset_config(client);
    if (!options) return 1;

    if (options->timeout_ms > 0) {
        client->timeout_ms = options->timeout_ms;
    }

    if (options->bearer_token) {
        client->bearer_token = waas_strdup(options->bearer_token);
        if (!client->bearer_token) {
            waas_wallet_client_reset_config(client);
            return 0;
        }
    }

    if (options->headers_count > 0) {
        if (!options->headers) {
            waas_wallet_client_reset_config(client);
            return 0;
        }
        for (size_t i = 0; i < options->headers_count; ++i) {
            if (!options->headers[i]) {
                waas_wallet_client_reset_config(client);
                return 0;
            }
            struct curl_slist *next = curl_slist_append(client->default_headers, options->headers[i]);
            if (!next) {
                waas_wallet_client_reset_config(client);
                return 0;
            }
            client->default_headers = next;
        }
    }

    return 1;
}

waas_wallet_client *waas_wallet_client_create(const char *base_url, const waas_client_options *options) {
    waas_wallet_client *client =
        (waas_wallet_client *)calloc(1, sizeof(*client));
    if (!client) return NULL;
    client->base_url = waas_strdup(base_url ? base_url : "");
    if (!client->base_url) {
        free(client);
        return NULL;
    }
    waas_wallet_client_reset_config(client);
    if (!waas_wallet_client_configure(client, options)) {
        free(client->base_url);
        client->base_url = NULL;
        waas_wallet_client_reset_config(client);
        free(client);
        return NULL;
    }
    return client;
}

void waas_wallet_client_destroy(waas_wallet_client *client) {
    if (!client) return;
    free(client->base_url);
    client->base_url = NULL;
    waas_wallet_client_reset_config(client);
    free(client);
}

int waas_wallet_client_send_prepared_request(
    waas_wallet_client *client,
    const waas_prepared_request *request,
    waas_http_response *response,
    waas_error *error
) {
    if (!client || !request || !response) {
        waas_set_error(error, 0, 0, "ClientError", "client, request, and response must be non-NULL", NULL);
        return -1;
    }

    return waas_http_send_request(
        client->base_url,
        request,
        client->bearer_token,
        client->default_headers,
        client->timeout_ms,
        response,
        error
    );
}
